<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Desktop Environment</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', 'Ubuntu', sans-serif;
            background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
            height: 100vh;
            overflow: hidden;
        }

        #desktop {
            width: 100%;
            height: 100%;
            display: flex;
            flex-direction: column;
            background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
            position: relative;
        }

        #wallpaper {
            flex: 1;
            background: linear-gradient(135deg, #0f3460 0%, #16213e 100%);
            position: relative;
            overflow: hidden;
        }

        #taskbar {
            height: 50px;
            background: rgba(20, 20, 30, 0.95);
            border-top: 1px solid rgba(255, 255, 255, 0.1);
            display: flex;
            align-items: center;
            padding: 0 20px;
            gap: 10px;
            backdrop-filter: blur(10px);
        }

        .taskbar-btn {
            height: 36px;
            padding: 0 16px;
            background: rgba(100, 150, 255, 0.2);
            border: 1px solid rgba(100, 150, 255, 0.4);
            border-radius: 6px;
            color: #fff;
            cursor: pointer;
            font-size: 13px;
            font-weight: 500;
            transition: all 0.2s;
            display: flex;
            align-items: center;
        }

        .taskbar-btn:hover {
            background: rgba(100, 150, 255, 0.4);
            border-color: rgba(100, 150, 255, 0.6);
        }

        .taskbar-btn:active {
            transform: scale(0.98);
        }

        .window {
            position: absolute;
            background: #2a2a3e;
            border: 1px solid rgba(255, 255, 255, 0.1);
            border-radius: 8px;
            box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
            display: flex;
            flex-direction: column;
            min-width: 360px;
            min-height: 240px;
        }

        .window.hidden {
            display: none;
        }

        .win-titlebar {
            height: 35px;
            background: linear-gradient(180deg, #3a3a52 0%, #2a2a3e 100%);
            border-bottom: 1px solid rgba(255, 255, 255, 0.05);
            display: flex;
            align-items: center;
            justify-content: space-between;
            padding: 0 12px;
            cursor: move;
            user-select: none;
            border-radius: 8px 8px 0 0;
        }

        .win-title {
            color: #fff;
            font-size: 13px;
            font-weight: 500;
            flex: 1;
        }

        .win-close {
            width: 24px;
            height: 24px;
            background: rgba(255, 100, 100, 0.3);
            border: 1px solid rgba(255, 100, 100, 0.5);
            border-radius: 4px;
            cursor: pointer;
            display: flex;
            align-items: center;
            justify-content: center;
            color: #ff6464;
            font-size: 14px;
            font-weight: bold;
            transition: all 0.2s;
        }

        .win-close:hover {
            background: rgba(255, 100, 100, 0.5);
            border-color: rgba(255, 100, 100, 0.8);
        }

        .win-content {
            flex: 1;
            background: #252535;
            border-radius: 0 0 8px 8px;
            display: flex;
            flex-direction: column;
            overflow: hidden;
        }

        #files-window {
            width: 600px;
            height: 400px;
            left: 50px;
            top: 100px;
        }

        .files-header {
            padding: 12px;
            border-bottom: 1px solid rgba(255, 255, 255, 0.05);
            display: flex;
            gap: 8px;
            align-items: center;
        }

        #files-up {
            padding: 6px 12px;
            background: rgba(100, 150, 255, 0.2);
            border: 1px solid rgba(100, 150, 255, 0.4);
            border-radius: 4px;
            color: #fff;
            cursor: pointer;
            font-size: 12px;
            transition: all 0.2s;
        }

        #files-up:hover {
            background: rgba(100, 150, 255, 0.4);
            border-color: rgba(100, 150, 255, 0.6);
        }

        #files-path {
            flex: 1;
            color: #aaa;
            font-family: monospace;
            font-size: 12px;
            padding: 6px 8px;
            background: rgba(0, 0, 0, 0.3);
            border-radius: 4px;
            overflow: hidden;
            text-overflow: ellipsis;
            white-space: nowrap;
        }

        .files-list {
            flex: 1;
            overflow-y: auto;
            padding: 8px;
            display: flex;
            flex-direction: column;
            gap: 2px;
        }

        .fs-item {
            padding: 8px 12px;
            color: #ccc;
            cursor: pointer;
            border-radius: 4px;
            user-select: none;
            font-size: 13px;
            transition: all 0.15s;
            white-space: nowrap;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .fs-item:hover {
            background: rgba(100, 150, 255, 0.2);
            color: #fff;
        }

        .fs-item.folder::before {
            content: '📁 ';
            margin-right: 4px;
        }

        .fs-item.file::before {
            content: '📄 ';
            margin-right: 4px;
        }

        #notepad-window {
            width: 700px;
            height: 500px;
            right: 50px;
            top: 100px;
        }

        .notepad-container {
            display: flex;
            flex-direction: column;
            height: 100%;
        }

        .notepad-header {
            padding: 8px 12px;
            border-bottom: 1px solid rgba(255, 255, 255, 0.05);
            display: flex;
            gap: 8px;
            align-items: center;
        }

        #new-tab {
            padding: 6px 12px;
            background: rgba(100, 150, 255, 0.2);
            border: 1px solid rgba(100, 150, 255, 0.4);
            border-radius: 4px;
            color: #fff;
            cursor: pointer;
            font-size: 12px;
            transition: all 0.2s;
            white-space: nowrap;
        }

        #new-tab:hover {
            background: rgba(100, 150, 255, 0.4);
            border-color: rgba(100, 150, 255, 0.6);
        }

        #tabs {
            display: flex;
            gap: 4px;
            padding: 8px 12px;
            border-bottom: 1px solid rgba(255, 255, 255, 0.05);
            overflow-x: auto;
            align-items: center;
        }

        .tab {
            padding: 6px 12px;
            background: rgba(255, 255, 255, 0.05);
            border: 1px solid rgba(255, 255, 255, 0.1);
            border-radius: 4px 4px 0 0;
            color: #aaa;
            cursor: pointer;
            font-size: 12px;
            transition: all 0.2s;
            user-select: none;
            white-space: nowrap;
            max-width: 150px;
            overflow: hidden;
            text-overflow: ellipsis;
        }

        .tab:hover {
            background: rgba(255, 255, 255, 0.1);
            color: #ccc;
        }

        .tab.active {
            background: #252535;
            border-color: rgba(100, 150, 255, 0.6);
            color: #fff;
        }

        #editor {
            flex: 1;
            background: #1a1a28;
            border: none;
            color: #ccc;
            padding: 12px;
            font-family: 'Courier New', monospace;
            font-size: 13px;
            line-height: 1.5;
            resize: none;
            outline: none;
        }

        #editor::placeholder {
            color: #666;
        }

        ::-webkit-scrollbar {
            width: 8px;
            height: 8px;
        }

        ::-webkit-scrollbar-track {
            background: rgba(0, 0, 0, 0.2);
        }

        ::-webkit-scrollbar-thumb {
            background: rgba(100, 150, 255, 0.3);
            border-radius: 4px;
        }

        ::-webkit-scrollbar-thumb:hover {
            background: rgba(100, 150, 255, 0.5);
        }
    </style>
</head>
<body>
    <div id="desktop">
        <div id="wallpaper"></div>
        <div id="taskbar">
            <button id="open-files" class="taskbar-btn">📁 Files</button>
            <button id="open-notepad" class="taskbar-btn">✎ Notepad</button>
        </div>
    </div>

    <div id="files-window" class="window hidden">
        <div class="win-titlebar">
            <div class="win-title">Files</div>
            <div class="win-close">✕</div>
        </div>
        <div class="win-content">
            <div class="files-header">
                <button id="files-up">← Up</button>
                <div id="files-path">/</div>
            </div>
            <div class="files-list" id="files-list"></div>
        </div>
    </div>

    <div id="notepad-window" class="window hidden">
        <div class="win-titlebar">
            <div class="win-title">Notepad</div>
            <div class="win-close">✕</div>
        </div>
        <div class="win-content notepad-container">
            <div class="notepad-header">
                <button id="new-tab">+ New Tab</button>
            </div>
            <div id="tabs"></div>
            <textarea id="editor" placeholder="Start typing..."></textarea>
        </div>
    </div>

    <script>
        const filesystem = {
            '/': {
                type: 'folder',
                children: {
                    'bin': { type: 'folder', children: {} },
                    'etc': { type: 'folder', children: {} },
                    'home': {
                        type: 'folder',
                        children: {
                            'user': {
                                type: 'folder',
                                children: {
                                    'Documents': { type: 'folder', children: {} },
                                    'Downloads': { type: 'folder', children: {} },
                                    'Pictures': { type: 'folder', children: {} },
                                    'readme.txt': { type: 'file' }
                                }
                            }
                        }
                    },
                    'usr': { type: 'folder', children: {} },
                    'var': { type: 'folder', children: {} }
                }
            }
        };

        let currentPath = '/';

        function getNodeAtPath(path) {
            if (path === '/') return filesystem['/'];
            const parts = path.split('/').filter(p => p);
            let node = filesystem['/'];
            for (const part of parts) {
                if (!node.children || !node.children[part]) return null;
                node = node.children[part];
            }
            return node;
        }

        function renderFilesList() {
            const node = getNodeAtPath(currentPath);
            const list = document.getElementById('files-list');
            list.innerHTML = '';

            if (!node || !node.children) return;

            const items = Object.entries(node.children).sort((a, b) => {
                if (a[1].type !== b[1].type) return a[1].type === 'folder' ? -1 : 1;
                return a[0].localeCompare(b[0]);
            });

            for (const [name, entry] of items) {
                const item = document.createElement('div');
                item.className = `fs-item ${entry.type}`;
                item.textContent = name;

                if (entry.type === 'folder') {
                    item.addEventListener('dblclick', () => {
                        const newPath = currentPath === '/' ? `/${name}` : `${currentPath}/${name}`;
                        currentPath = newPath;
                        document.getElementById('files-path').textContent = newPath;
                        renderFilesList();
                    });
                }

                list.appendChild(item);
            }
        }

        document.getElementById('files-up').addEventListener('click', () => {
            if (currentPath === '/') return;
            currentPath = currentPath.split('/').slice(0, -1).join('/') || '/';
            document.getElementById('files-path').textContent = currentPath;
            renderFilesList();
        });

        const STORAGE_KEY = 'notepad_tabs';
        let tabs = [];
        let activeTabId = null;

        function loadTabs() {
            const saved = localStorage.getItem(STORAGE_KEY);
            if (saved) {
                try {
                    tabs = JSON.parse(saved);
                    if (tabs.length > 0) {
                        activeTabId = tabs[0].id;
                    }
                } catch (e) {
                    tabs = [];
                }
            }
            if (tabs.length === 0) {
                tabs = [{ id: Date.now(), title: 'Untitled', content: '' }];
                activeTabId = tabs[0].id;
            }
        }

        function saveTabs() {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(tabs));
        }

        function renderTabs() {
            const tabsContainer = document.getElementById('tabs');
            tabsContainer.innerHTML = '';

            for (const tab of tabs) {
                const tabEl = document.createElement('div');
                tabEl.className = `tab ${tab.id === activeTabId ? 'active' : ''}`;
                tabEl.textContent = tab.title || 'Untitled';
                tabEl.addEventListener('click', () => switchTab(tab.id));
                tabsContainer.appendChild(tabEl);
            }

            updateEditor();
        }

        function switchTab(tabId) {
            const currentTab = tabs.find(t => t.id === activeTabId);
            if (currentTab) {
                currentTab.content = document.getElementById('editor').value;
            }
            activeTabId = tabId;
            saveTabs();
            renderTabs();
        }

        function updateEditor() {
            const activeTab = tabs.find(t => t.id === activeTabId);
            const editor = document.getElementById('editor');
            if (activeTab) {
                editor.value = activeTab.content;
            }
        }

        document.getElementById('editor').addEventListener('input', (e) => {
            const activeTab = tabs.find(t => t.id === activeTabId);
            if (activeTab) {
                activeTab.content = e.target.value;
                saveTabs();
            }
        });

        document.getElementById('new-tab').addEventListener('click', () => {
            const newTab = { id: Date.now(), title: 'Untitled', content: '' };
            tabs.push(newTab);
            activeTabId = newTab.id;
            saveTabs();
            renderTabs();
        });

        function setupWindow(windowId, openBtnId) {
            const windowEl = document.getElementById(windowId);
            const openBtn = document.getElementById(openBtnId);
            const closeBtn = windowEl.querySelector('.win-close');
            const titlebar = windowEl.querySelector('.win-titlebar');

            openBtn.addEventListener('click', () => {
                windowEl.classList.remove('hidden');
                windowEl.style.zIndex = getMaxZIndex() + 1;
            });

            closeBtn.addEventListener('click', () => {
                windowEl.classList.add('hidden');
            });

            titlebar.addEventListener('mousedown', (e) => {
                if (e.target.closest('.win-close')) return;
                const rect = windowEl.getBoundingClientRect();
                const startX = e.clientX - rect.left;
                const startY = e.clientY - rect.top;

                function onMouseMove(move) {
                    windowEl.style.left = (move.clientX - startX) + 'px';
                    windowEl.style.top = (move.clientY - startY) + 'px';
                }

                function onMouseUp() {
                    document.removeEventListener('mousemove', onMouseMove);
                    document.removeEventListener('mouseup', onMouseUp);
                }

                document.addEventListener('mousemove', onMouseMove);
                document.addEventListener('mouseup', onMouseUp);
            });

            windowEl.addEventListener('mousedown', () => {
                windowEl.style.zIndex = getMaxZIndex() + 1;
            });
        }

        function getMaxZIndex() {
            return Math.max(...Array.from(document.querySelectorAll('.window')).map(w => parseInt(window.getComputedStyle(w).zIndex) || 0), 0);
        }

        setupWindow('files-window', 'open-files');
        setupWindow('notepad-window', 'open-notepad');

        loadTabs();
        renderFilesList();
        renderTabs();
    </script>
</body>
</html>
